import{_ as a,o as t,c as r,a7 as l}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Awakener Leveling Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/awakeners/leveling.md","filePath":"en/awakeners/leveling.md","lastUpdated":1775394001000}'),i={name:"en/awakeners/leveling.md"};function s(n,e,o,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="awakener-leveling-guide" tabindex="-1">Awakener Leveling Guide <a class="header-anchor" href="#awakener-leveling-guide" aria-label="Permalink to &quot;Awakener Leveling Guide&quot;">​</a></h1><p>Leveling is the primary way to increase an Awakener&#39;s base stats (Constitution, Attack, Defense). This page covers experience materials, level caps, and skill unlocks.</p><h2 id="experience-materials" tabindex="-1">Experience Materials <a class="header-anchor" href="#experience-materials" aria-label="Permalink to &quot;Experience Materials&quot;">​</a></h2><p>Awakeners gain experience through dedicated XP materials obtained from resource stages, event rewards, and daily tasks.</p><table tabindex="0"><thead><tr><th>Material</th><th>XP Granted</th><th>Source</th></tr></thead><tbody><tr><td><em>To be added</em></td><td>—</td><td>Resource Stages, Events</td></tr><tr><td><em>To be added</em></td><td>—</td><td>Resource Stages, Events</td></tr><tr><td><em>To be added</em></td><td>—</td><td>Resource Stages, Events</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Focus your XP materials on your main DPS Awakener first. A single strong carry will progress you further than spreading resources thin across multiple characters.</p></div><h2 id="level-caps-and-ascension" tabindex="-1">Level Caps and Ascension <a class="header-anchor" href="#level-caps-and-ascension" aria-label="Permalink to &quot;Level Caps and Ascension&quot;">​</a></h2><p>Awakeners have level caps that require ascension materials to break through.</p><p><em>To be added — ascension breakpoint table</em></p><h2 id="skill-unlock-at-level-25" tabindex="-1">Skill Unlock at Level 25 <a class="header-anchor" href="#skill-unlock-at-level-25" aria-label="Permalink to &quot;Skill Unlock at Level 25&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Awakeners unlock an additional skill enhancement at <strong>Level 25</strong>. Make sure to level your core team members to at least 25 to access their full kit.</p></div><p>Reaching Level 25 unlocks a passive or enhanced effect for one of the Awakener&#39;s Command Cards. The specific unlock varies by character.</p><h2 id="leveling-priority" tabindex="-1">Leveling Priority <a class="header-anchor" href="#leveling-priority" aria-label="Permalink to &quot;Leveling Priority&quot;">​</a></h2><ol><li><strong>Main DPS</strong> — Level as high as possible for maximum damage output</li><li><strong>Sub-DPS / Secondary Carry</strong> — Level to at least 25 for skill unlock</li><li><strong>Support</strong> — Level to 25 for skill unlock; further levels add survivability</li><li><strong>Tank</strong> — Benefits greatly from Constitution scaling; level after supports if resources are limited</li></ol><h2 id="material-farming" tabindex="-1">Material Farming <a class="header-anchor" href="#material-farming" aria-label="Permalink to &quot;Material Farming&quot;">​</a></h2><p>XP materials are primarily farmed from <a href="./../stages/resource.html">Resource Stages</a>. Check <a href="./../guides/dailies.html">Daily Tasks</a> for additional sources.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Awakener Overview</a></li><li><a href="./enlightenment.html">Enlightenment</a></li><li><a href="./../stages/resource.html">Resource Stages</a></li></ul>',18)])])}const p=a(i,[["render",s]]);export{m as __pageData,p as default};
